SELECT SUM(total_vacancies) AS total_vacancies
FROM job_vacancies
WHERE mun_id = '1' AND yr = 2023;

SELECT AVG(employment_rate) AS average_employment_rate
FROM employment_rates
WHERE mun_id = '1';

SELECT cat_id, val
FROM employment_data
WHERE mun_id = '0' AND yr = 2021;

SELECT SUM(val) AS total_value
FROM employment_data
WHERE mun_id = '0' AND yr = 2021;

SELECT SUM(total_vacancies) AS total_vacancies
FROM job_vacancies
WHERE mun_id = '0' AND yr = 2023;

SELECT SUM(val) AS total_job_applicants
FROM employment_data
WHERE mun_id = '0' AND yr = 2023 AND cat_id = 'job_applicants';

SELECT yr, cat_id, val
FROM employment_data
WHERE yr = 2021 AND cat_id = '1';

SELECT mun_name
FROM municipalities
WHERE population = (SELECT MAX(population) FROM municipalities);

SELECT AVG(val) AS average_employment_statistic
FROM employment_data
WHERE mun_id = '1' AND yr = 2020;

SELECT AVG(employment_rate) AS avg_employment_rate
FROM employment_rates
WHERE yr = 2023;
